+    #[test]
+    fn lerp_color_at_zero_returns_first() {
+        let a = PackedRgba::rgb(10, 20, 30);
+        let b = PackedRgba::rgb(200, 180, 160);
+        let result = lerp_color(a, b, 0.0);
