+    #[test]
+    fn lerp_color_at_one_returns_second() {
+        let a = PackedRgba::rgb(10, 20, 30);
+        let b = PackedRgba::rgb(200, 180, 160);
+        let result = lerp_color(a, b, 1.0);
+        assert_eq!(result.r(), 200);
+        assert_eq!(result.g(), 180);
+        assert_eq!(result.b(), 160);
+    }
